    <script>
        // Function to generate Fibonacci numbers
        function getFibonacciSequence(n, initialFibs) {
            const fib = [...initialFibs];
            while (fib.length < n) {
                fib.push(fib[fib.length - 1] + fib[fib.length - 2]);
            }
            return fib;
        }

        // Function to draw a Fibonacci spiral
        function drawFibonacciSpiral(canvasId, initialFibSequence, color) {
            const canvas = document.getElementById(canvasId);
            if (!canvas) {
                console.error(`Canvas with ID '${canvasId}' not found.`);
                return;
            }
            const ctx = canvas.getContext('2d');
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            ctx.lineWidth = 2;
            ctx.strokeStyle = color;

            const maxFibCount = 10; // Number of Fibonacci numbers to use for the spiral
            const fibs = getFibonacciSequence(maxFibCount, initialFibSequence);

            // Start drawing from the center, adjust as needed
