            // The 'center' of the arc is always a corner of the square that defines its radius.
            // The spiral rotates, and so does the point around which the arc is drawn.

            // Let's set up initial square positions to build the spiral outwards
            // We'll place the initial '1x1' square (scaled) relative to the canvas center.
            // The spiral will grow from a central point.

            // Initial position (top-left corner of the first square)
            let x = currentX - (fibs[3] + fibs[2]) * scale / 2; // Adjust starting point to center the spiral roughly
            let y = currentY - (fibs[3] + fibs[2]) * scale / 2;

            let direction = 0; // 0: right, 1: down, 2: left, 3: up
            let quadrant = 0; // 0: top-right, 1: bottom-right, 2: bottom-left, 3: top-left

            for (let i = 0; i < fibs.length; i++) {
                const radius = fibs[i] * scale;

                let arcX, arcY, startAngle, endAngle;

                // The logic for positioning the arc's center (arcX, arcY) and its angles
                // depends on the current 'quadrant' or direction of the spiral.
                // Each arc is a quarter circle.

                switch (quadrant) {
                    case 0: // Arc from right to down (center is top-left corner of current square)
                        arcX = x + radius;
                        arcY = y;
                        startAngle = Math.PI; // 180 degrees
                        endAngle = Math.PI / 2; // 90 degrees
                        // Next square's top-left corner is now at (x, y + radius)
                        y += radius;
                        break;
                    case 1: // Arc from down to left (center is top-right corner)
                        arcX = x + radius;
                        arcY = y + radius;
                        startAngle = Math.PI / 2; // 90 degrees
                        endAngle = 0; // 0 degrees (or 2*Math.PI)
                        // Next square's top-left corner is now at (x - radius, y)
                        x -= radius;
                        break;
                    case 2: // Arc from left to up (center is bottom-right corner)
                        arcX = x;
                        arcY = y + radius;
                        startAngle = 0; // 0 degrees
                        endAngle = -Math.PI / 2; // -90 degrees (or 3*Math.PI/2)
                        // Next square's top-left corner is now at (x, y - radius)
                        y -= radius;
                        break;
                    case 3: // Arc from up to right (center is bottom-left corner)
                        arcX = x;
                        arcY = y;
                        startAngle = -Math.PI / 2; // -90 degrees
                        endAngle = Math.PI; // 180 degrees (or 2*Math.PI - Math.PI/2)
                        // Next square's top-left corner is now at (x + radius, y)
                        x += radius;
                        break;
                }

                ctx.beginPath();
                ctx.arc(arcX, arcY, radius, startAngle, endAngle, true); // true for counter-clockwise
                ctx.stroke();

                quadrant = (quadrant + 1) % 4; // Move to the next quadrant
            }
        }
        drawFixedSpiral(fixedCtx, fibNumbers);

